import { useEditor, EditorContent, BubbleMenu } from '@tiptap/react';
import StarterKit from '@tiptap/starter-kit';
import TipTapImage from '@tiptap/extension-image';
import Link from '@tiptap/extension-link';
import Placeholder from '@tiptap/extension-placeholder';
import Youtube from '@tiptap/extension-youtube';
import CodeBlockLowlight from '@tiptap/extension-code-block-lowlight';
import { common, createLowlight } from 'lowlight';
import { api } from '../utils/api';

const lowlight = createLowlight(common);

interface EditorProps {
  content: Record<string, unknown>;
  onChange: (json: Record<string, unknown>, html: string) => void;
}

export default function Editor({ content, onChange }: EditorProps) {
  const editor = useEditor({
    extensions: [
      StarterKit.configure({ codeBlock: false }),
      TipTapImage.configure({ allowBase64: false }),
      Link.configure({ openOnClick: false, autolink: true }),
      Placeholder.configure({ placeholder: 'Start writing your article...' }),
      Youtube.configure({ width: 640, height: 360 }),
      CodeBlockLowlight.configure({ lowlight }),
    ],
    content,
    onUpdate: ({ editor: e }) => {
      onChange(e.getJSON(), e.getHTML());
    },
  });

  const addImage = async () => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.onchange = async () => {
      const file = input.files?.[0];
      if (!file) return;
      const form = new FormData();
      form.append('file', file);
      const res = await api.post('/media/upload', form);
      editor?.chain().focus().setImage({ src: res.data.url, alt: res.data.alt_text }).run();
    };
    input.click();
  };

  const addYouTube = () => {
    const url = prompt('Enter YouTube URL:');
    if (url) editor?.commands.setYoutubeVideo({ src: url });
  };

  if (!editor) return null;

  return (
    <div className="editor-wrapper">
      <div className="toolbar">
        <button onClick={() => editor.chain().focus().toggleBold().run()}
                className={editor.isActive('bold') ? 'active' : ''}>B</button>
        <button onClick={() => editor.chain().focus().toggleItalic().run()}
                className={editor.isActive('italic') ? 'active' : ''}>I</button>
        <button onClick={() => editor.chain().focus().toggleHeading({ level: 2 }).run()}
                className={editor.isActive('heading', { level: 2 }) ? 'active' : ''}>H2</button>
        <button onClick={() => editor.chain().focus().toggleHeading({ level: 3 }).run()}
                className={editor.isActive('heading', { level: 3 }) ? 'active' : ''}>H3</button>
        <button onClick={() => editor.chain().focus().toggleBulletList().run()}
                className={editor.isActive('bulletList') ? 'active' : ''}>List</button>
        <button onClick={() => editor.chain().focus().toggleOrderedList().run()}
                className={editor.isActive('orderedList') ? 'active' : ''}>Ordered</button>
        <button onClick={() => editor.chain().focus().toggleBlockquote().run()}
                className={editor.isActive('blockquote') ? 'active' : ''}>Quote</button>
        <button onClick={() => editor.chain().focus().toggleCodeBlock().run()}
                className={editor.isActive('codeBlock') ? 'active' : ''}>Code</button>
        <button onClick={addImage}>Image</button>
        <button onClick={addYouTube}>YouTube</button>
        <button onClick={() => editor.chain().focus().setHorizontalRule().run()}>HR</button>
      </div>
      {editor && (
        <BubbleMenu editor={editor} tippyOptions={{ duration: 150 }}>
          <div className="bubble-menu">
            <button onClick={() => editor.chain().focus().toggleBold().run()}>B</button>
            <button onClick={() => editor.chain().focus().toggleItalic().run()}>I</button>
            <button onClick={() => {
              const url = prompt('Link URL:');
              if (url) editor.chain().focus().setLink({ href: url }).run();
            }}>Link</button>
          </div>
        </BubbleMenu>
      )}
      <EditorContent editor={editor} className="editor-content" />
    </div>
  );
}

import { useState, useCallback, useMemo } from 'react';
import { createEditor, Descendant, Element as SlateElement, Text } from 'slate';
import { Slate, Editable, withReact, RenderElementProps, RenderLeafProps } from 'slate-react';
import { withHistory } from 'slate-history';
import { api } from '../utils/api';

interface SlateEditorProps {
  initialValue: Descendant[];
  onChange: (value: Descendant[]) => void;
}

const Element = ({ attributes, children, element }: RenderElementProps) => {
  switch ((element as SlateElement & { type: string }).type) {
    case 'heading-two':
      return <h2 {...attributes}>{children}</h2>;
    case 'heading-three':
      return <h3 {...attributes}>{children}</h3>;
    case 'block-quote':
      return <blockquote {...attributes}>{children}</blockquote>;
    case 'bulleted-list':
      return <ul {...attributes}>{children}</ul>;
    case 'list-item':
      return <li {...attributes}>{children}</li>;
    case 'image':
      return (
        <div {...attributes} contentEditable={false}>
          <img src={(element as SlateElement & { url: string }).url} alt="" style={{ maxWidth: '100%' }} />
          {children}
        </div>
      );
    default:
      return <p {...attributes}>{children}</p>;
  }
};

const Leaf = ({ attributes, children, leaf }: RenderLeafProps) => {
  const l = leaf as Text & { bold?: boolean; italic?: boolean; code?: boolean };
  if (l.bold) children = <strong>{children}</strong>;
  if (l.italic) children = <em>{children}</em>;
  if (l.code) children = <code>{children}</code>;
  return <span {...attributes}>{children}</span>;
};

export default function SlateEditor({ initialValue, onChange }: SlateEditorProps) {
  const editor = useMemo(() => withHistory(withReact(createEditor())), []);
  const [value, setValue] = useState<Descendant[]>(initialValue);

  const renderElement = useCallback((props: RenderElementProps) => <Element {...props} />, []);
  const renderLeaf = useCallback((props: RenderLeafProps) => <Leaf {...props} />, []);

  return (
    <Slate editor={editor} initialValue={value} onChange={(v) => { setValue(v); onChange(v); }}>
      <Editable
        renderElement={renderElement}
        renderLeaf={renderLeaf}
        placeholder="Start writing..."
        spellCheck
      />
    </Slate>
  );
}

import { useState } from 'react';
import ReactMarkdown from 'react-markdown';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { oneDark } from 'react-syntax-highlighter/dist/esm/styles/prism';
import remarkGfm from 'remark-gfm';

interface MarkdownEditorProps {
  value: string;
  onChange: (md: string) => void;
}

export default function MarkdownEditor({ value, onChange }: MarkdownEditorProps) {
  const [tab, setTab] = useState<'write' | 'preview'>('write');

  return (
    <div className="md-editor">
      <div className="md-tabs">
        <button className={tab === 'write' ? 'active' : ''} onClick={() => setTab('write')}>Write</button>
        <button className={tab === 'preview' ? 'active' : ''} onClick={() => setTab('preview')}>Preview</button>
      </div>
      {tab === 'write' ? (
        <textarea
          value={value}
          onChange={(e) => onChange(e.target.value)}
          className="md-textarea"
          placeholder="Write in Markdown..."
          rows={20}
        />
      ) : (
        <div className="md-preview">
          <ReactMarkdown
            remarkPlugins={[remarkGfm]}
            components={{
              code({ className, children, ...props }) {
                const match = /language-(\w+)/.exec(className || '');
                return match ? (
                  <SyntaxHighlighter style={oneDark} language={match[1]} PreTag="div">
                    {String(children).replace(/\n$/, '')}
                  </SyntaxHighlighter>
                ) : (
                  <code className={className} {...props}>{children}</code>
                );
              },
            }}
          >
            {value}
          </ReactMarkdown>
        </div>
      )}
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import Editor from '../components/Editor';
import { api } from '../utils/api';

interface Category { id: number; name: string; slug: string; }

export default function AdminArticleEditor() {
  const { slug } = useParams();
  const navigate = useNavigate();
  const [title, setTitle] = useState('');
  const [excerpt, setExcerpt] = useState('');
  const [categoryId, setCategoryId] = useState<number | null>(null);
  const [tagInput, setTagInput] = useState('');
  const [tags, setTags] = useState<string[]>([]);
  const [coverUrl, setCoverUrl] = useState('');
  const [contentJson, setContentJson] = useState<Record<string, unknown>>({});
  const [contentHtml, setContentHtml] = useState('');
  const [categories, setCategories] = useState<Category[]>([]);
  const [saving, setSaving] = useState(false);
  const [scheduledAt, setScheduledAt] = useState('');
  const [lastSaved, setLastSaved] = useState<Date | null>(null);
  const autosaveTimer = useRef<ReturnType<typeof setTimeout>>();

  useEffect(() => {
    api.get('/categories').then((r) => setCategories(r.data));
    if (slug) {
      api.get(`/articles/${slug}`).then((r) => {
        const a = r.data;
        setTitle(a.title);
        setExcerpt(a.excerpt);
        setCategoryId(a.category_id);
        setTags(a.tags.map((t: { name: string }) => t.name));
        setCoverUrl(a.cover_image_url || '');
        setContentJson(a.content_json);
        setContentHtml(a.content_html);
      });
    }
  }, [slug]);

  // Autosave draft every 30 seconds
  useEffect(() => {
    if (!slug || !title) return;
    if (autosaveTimer.current) clearTimeout(autosaveTimer.current);
    autosaveTimer.current = setTimeout(async () => {
      await save('draft', true);
    }, 30000);
    return () => { if (autosaveTimer.current) clearTimeout(autosaveTimer.current); };
  }, [contentJson, title, excerpt]);

  const addTag = () => {
    const t = tagInput.trim().toLowerCase();
    if (t && !tags.includes(t)) setTags([...tags, t]);
    setTagInput('');
  };

  const save = async (status: string, isAutosave = false) => {
    if (saving) return;
    setSaving(true);
    const payload = {
      title, excerpt, category_id: categoryId, tags,
      cover_image_url: coverUrl, content_json: contentJson,
      content_html: contentHtml, status,
    };
    try {
      if (slug) {
        await api.put(`/articles/${slug}`, payload);
      } else {
        const res = await api.post('/articles', payload);
        navigate(`/admin/articles/${res.data.slug}`, { replace: true });
      }
      setLastSaved(new Date());
    } finally {
      setSaving(false);
    }
  };

  const handlePublish = async () => {
    await save('draft');
    if (scheduledAt) {
      await api.post(`/articles/${slug}/publish`, { scheduled_at: scheduledAt });
    } else {
      await api.post(`/articles/${slug}/publish`);
    }
  };

  return (
    <div className="admin-editor">
      <input className="title-input" value={title}
             onChange={(e) => setTitle(e.target.value)} placeholder="Article title" />
      <input className="excerpt-input" value={excerpt}
             onChange={(e) => setExcerpt(e.target.value)} placeholder="Short excerpt (max 300 chars)" />
      <div className="meta-row">
        <select value={categoryId ?? ''} onChange={(e) => setCategoryId(Number(e.target.value))}>
          <option value="">Select category</option>
          {categories.map((c) => <option key={c.id} value={c.id}>{c.name}</option>)}
        </select>
        <div className="tag-input">
          <input value={tagInput} onChange={(e) => setTagInput(e.target.value)}
                 onKeyDown={(e) => e.key === 'Enter' && (e.preventDefault(), addTag())}
                 placeholder="Add tag" />
          {tags.map((t) => (
            <span key={t} className="tag-chip">
              {t} <button onClick={() => setTags(tags.filter((x) => x !== t))}>x</button>
            </span>
          ))}
        </div>
        <div className="schedule-input">
          <label>Schedule for:</label>
          <input type="datetime-local" value={scheduledAt}
                 onChange={(e) => setScheduledAt(e.target.value)} />
        </div>
      </div>
      <Editor content={contentJson} onChange={(json, html) => { setContentJson(json); setContentHtml(html); }} />
      <div className="editor-actions">
        <span className="autosave-status">
          {lastSaved ? `Last saved ${lastSaved.toLocaleTimeString()}` : ''}
        </span>
        <button onClick={() => save('draft')} disabled={saving}>Save Draft</button>
        <button onClick={handlePublish} disabled={saving} className="btn-publish">
          {scheduledAt ? 'Schedule' : 'Publish'}
        </button>
      </div>
    </div>
  );
}

import { useEffect, useState } from 'react';

interface TocItem {
  id: string;
  text: string;
  level: number;
}

export default function TableOfContents({ contentHtml }: { contentHtml: string }) {
  const [items, setItems] = useState<TocItem[]>([]);
  const [activeId, setActiveId] = useState('');

  useEffect(() => {
    const parser = new DOMParser();
    const doc = parser.parseFromString(contentHtml, 'text/html');
    const headings = doc.querySelectorAll('h2, h3');
    const tocItems: TocItem[] = [];
    headings.forEach((h, i) => {
      const id = h.id || `heading-${i}`;
      tocItems.push({ id, text: h.textContent || '', level: parseInt(h.tagName[1]) });
    });
    setItems(tocItems);
  }, [contentHtml]);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) setActiveId(entry.target.id);
        });
      },
      { rootMargin: '-80px 0px -80% 0px' }
    );
    items.forEach(({ id }) => {
      const el = document.getElementById(id);
      if (el) observer.observe(el);
    });
    return () => observer.disconnect();
  }, [items]);

  if (items.length < 3) return null;

  return (
    <nav className="toc" aria-label="Table of contents">
      <h4>Contents</h4>
      <ul>
        {items.map(({ id, text, level }) => (
          <li key={id} style={{ paddingLeft: (level - 2) * 16 }}>
            <a href={`#${id}`}
               className={activeId === id ? 'active' : ''}
               onClick={(e) => {
                 e.preventDefault();
                 document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' });
               }}>
              {text}
            </a>
          </li>
        ))}
      </ul>
    </nav>
  );
}

import { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { api } from '../utils/api';
import SEO from '../components/SEO';
import TableOfContents from '../components/TableOfContents';

interface Article {
  title: string; slug: string; excerpt: string; content_html: string;
  cover_image_url: string; published_at: string; author_name: string;
  category_name: string; reading_time_minutes: number;
  tags: { name: string; slug: string }[];
}

interface RelatedArticle {
  title: string; slug: string; excerpt: string; cover_image_url: string;
}

export default function ArticlePage() {
  const { slug } = useParams<{ slug: string }>();
  const [article, setArticle] = useState<Article | null>(null);
  const [related, setRelated] = useState<RelatedArticle[]>([]);

  useEffect(() => {
    if (!slug) return;
    api.get(`/articles/${slug}`).then((r) => setArticle(r.data));
    api.get(`/articles/${slug}/related`).then((r) => setRelated(r.data.articles));
  }, [slug]);

  if (!article) return <div className="loading">Loading...</div>;

  return (
    <>
      <SEO title={article.title} description={article.excerpt}
           url={`https://example.com/articles/${article.slug}`}
           image={article.cover_image_url} />
      <article className="article-page">
        {article.cover_image_url && (
          <img src={article.cover_image_url} alt="" className="cover-image" loading="lazy" />
        )}
        <h1>{article.title}</h1>
        <div className="article-meta">
          <span>By {article.author_name}</span>
          <span>{new Date(article.published_at).toLocaleDateString()}</span>
          <span>{article.reading_time_minutes} min read</span>
          <Link to={`/category/${article.category_name}`}>{article.category_name}</Link>
        </div>
        <div className="article-layout">
          <TableOfContents contentHtml={article.content_html} />
          <div className="article-body" dangerouslySetInnerHTML={{ __html: article.content_html }} />
        </div>
        <div className="article-tags">
          {article.tags.map((t) => (
            <Link key={t.slug} to={`/tag/${t.slug}`} className="tag-link">{t.name}</Link>
          ))}
        </div>
      </article>
      {related.length > 0 && (
        <section className="related-articles">
          <h2>Related Articles</h2>
          <div className="related-grid">
            {related.map((r) => (
              <Link key={r.slug} to={`/articles/${r.slug}`} className="related-card">
                {r.cover_image_url && <img src={r.cover_image_url} alt="" loading="lazy" />}
                <h3>{r.title}</h3>
                <p>{r.excerpt}</p>
              </Link>
            ))}
          </div>
        </section>
      )}
    </>
  );
}

import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { api } from '../utils/api';

interface Tag { name: string; slug: string; count: number; }

export default function TagCloud() {
  const [tags, setTags] = useState<Tag[]>([]);

  useEffect(() => {
    api.get('/tags?with_counts=true').then((r) => setTags(r.data));
  }, []);

  const maxCount = Math.max(...tags.map((t) => t.count), 1);

  const fontSize = (count: number) => {
    const min = 0.75;
    const max = 2.0;
    return min + (count / maxCount) * (max - min);
  };

  return (
    <div className="tag-cloud" role="navigation" aria-label="Tags">
      {tags.map((tag) => (
        <Link key={tag.slug} to={`/tag/${tag.slug}`}
              className="tag-cloud-item"
              style={{ fontSize: `${fontSize(tag.count)}rem` }}>
          {tag.name}
          <span className="tag-count">({tag.count})</span>
        </Link>
      ))}
    </div>
  );
}

import { Link } from 'react-router-dom';

interface Crumb { name: string; slug: string; }

export default function Breadcrumbs({ crumbs }: { crumbs: Crumb[] }) {
  const structuredData = {
    '@context': 'https://schema.org',
    '@type': 'BreadcrumbList',
    'itemListElement': crumbs.map((c, i) => ({
      '@type': 'ListItem',
      'position': i + 1,
      'name': c.name,
      'item': `https://example.com/category/${c.slug}`,
    })),
  };

  return (
    <>
      <script type="application/ld+json" dangerouslySetInnerHTML={{ __html: JSON.stringify(structuredData) }} />
      <nav className="breadcrumbs" aria-label="Breadcrumb">
        <ol>
          <li><Link to="/">Home</Link></li>
          {crumbs.map((c, i) => (
            <li key={c.slug}>
              {i < crumbs.length - 1 ? (
                <Link to={`/category/${c.slug}`}>{c.name}</Link>
              ) : (
                <span aria-current="page">{c.name}</span>
              )}
            </li>
          ))}
        </ol>
      </nav>
    </>
  );
}

import { Helmet } from 'react-helmet-async';

interface SEOProps {
  title: string;
  description: string;
  url: string;
  image?: string;
  type?: string;
  publishedAt?: string;
  author?: string;
  tags?: string[];
}

export default function SEO({ title, description, url, image, type = 'article', publishedAt, author, tags }: SEOProps) {
  const siteName = 'My Content Platform';

  const structuredData = type === 'article' ? {
    '@context': 'https://schema.org',
    '@type': 'NewsArticle',
    'headline': title,
    'description': description,
    'url': url,
    'image': image,
    'datePublished': publishedAt,
    'author': { '@type': 'Person', 'name': author },
    'publisher': {
      '@type': 'Organization',
      'name': siteName,
      'logo': { '@type': 'ImageObject', 'url': 'https://example.com/logo.png' },
    },
    'keywords': tags?.join(', '),
  } : undefined;

  return (
    <Helmet>
      <title>{title} | {siteName}</title>
      <meta name="description" content={description} />
      <link rel="canonical" href={url} />
      <meta property="og:title" content={title} />
      <meta property="og:description" content={description} />
      <meta property="og:url" content={url} />
      <meta property="og:type" content={type} />
      <meta property="og:site_name" content={siteName} />
      {image && <meta property="og:image" content={image} />}
      {publishedAt && <meta property="article:published_time" content={publishedAt} />}
      <meta name="twitter:card" content="summary_large_image" />
      <meta name="twitter:title" content={title} />
      <meta name="twitter:description" content={description} />
      {image && <meta name="twitter:image" content={image} />}
      {structuredData && (
        <script type="application/ld+json">{JSON.stringify(structuredData)}</script>
      )}
    </Helmet>
  );
}

import { useEffect, useRef } from 'react';

interface AdSlotProps {
  adSlot: string;
  format?: 'auto' | 'rectangle' | 'horizontal' | 'vertical';
  className?: string;
}

export default function AdSlot({ adSlot, format = 'auto', className = '' }: AdSlotProps) {
  const adRef = useRef<HTMLModElement>(null);
  const pushed = useRef(false);

  useEffect(() => {
    if (pushed.current) return;
    try {
      const adsbygoogle = (window as unknown as { adsbygoogle: unknown[] }).adsbygoogle;
      adsbygoogle.push({});
      pushed.current = true;
    } catch {
      // AdSense not loaded or ad blocker active
    }
  }, []);

  return (
    <div className={`ad-container ${className}`}>
      <ins className="adsbygoogle"
           ref={adRef}
           style={{ display: 'block' }}
           data-ad-client="ca-pub-XXXXXXXXXXXXXXXX"
           data-ad-slot={adSlot}
           data-ad-format={format}
           data-full-width-responsive="true" />
    </div>
  );
}

import { useState, useEffect } from 'react';
import { api } from '../utils/api';

interface Comment {
  id: number;
  author_name: string;
  body: string;
  parent_id: number | null;
  created_at: string;
  likes: number;
  dislikes: number;
  children: Comment[];
}

function CommentItem({ comment, slug, onReply }: {
  comment: Comment; slug: string; onReply: (c: Comment) => void;
}) {
  const [replying, setReplying] = useState(false);
  const [text, setText] = useState('');
  const [likes, setLikes] = useState(comment.likes);

  const submit = async () => {
    if (!text.trim()) return;
    const res = await api.post(`/articles/${slug}/comments`, {
      body: text, parent_id: comment.id, author_name: 'Reader',
    });
    onReply({ ...res.data, author_name: 'Reader', children: [], likes: 0, dislikes: 0 });
    setText('');
    setReplying(false);
  };

  const react = async (reaction: string) => {
    const res = await api.post(`/comments/${comment.id}/react`, { reaction });
    setLikes(res.data.likes);
  };

  return (
    <div className="comment" style={{ marginLeft: comment.parent_id ? 24 : 0 }}>
      <div className="comment-header">
        <strong>{comment.author_name}</strong>
        <time>{new Date(comment.created_at).toLocaleDateString()}</time>
      </div>
      <p>{comment.body}</p>
      <div className="comment-actions">
        <button onClick={() => react('like')}>thumbs up {likes}</button>
        <button onClick={() => setReplying(!replying)}>Reply</button>
      </div>
      {replying && (
        <div className="reply-form">
          <textarea value={text} onChange={(e) => setText(e.target.value)}
                    placeholder="Write a reply..." rows={3} />
          <button onClick={submit}>Post Reply</button>
        </div>
      )}
      {comment.children.map((c) => (
        <CommentItem key={c.id} comment={c} slug={slug} onReply={onReply} />
      ))}
    </div>
  );
}

export default function CommentSection({ slug }: { slug: string }) {
  const [comments, setComments] = useState<Comment[]>([]);
  const [body, setBody] = useState('');
  const [name, setName] = useState('');

  useEffect(() => {
    api.get(`/articles/${slug}/comments`).then((r) => setComments(r.data.comments));
  }, [slug]);

  const submit = async () => {
    if (!body.trim()) return;
    const res = await api.post(`/articles/${slug}/comments`, {
      body, author_name: name || 'Anonymous',
    });
    if (res.data.status === 'approved') {
      setComments((prev) => [...prev, { ...res.data, author_name: name || 'Anonymous', children: [], likes: 0, dislikes: 0 }]);
    }
    setBody('');
  };

  const handleReply = (newComment: Comment) => {
    const addReply = (list: Comment[]): Comment[] =>
      list.map((c) =>
        c.id === newComment.parent_id
          ? { ...c, children: [...c.children, newComment] }
          : { ...c, children: addReply(c.children) }
      );
    setComments(addReply);
  };

  return (
    <section className="comment-section">
      <h3>Comments ({comments.length})</h3>
      <div className="comment-form">
        <input value={name} onChange={(e) => setName(e.target.value)} placeholder="Your name" />
        <textarea value={body} onChange={(e) => setBody(e.target.value)}
                  placeholder="Share your thoughts..." rows={4} />
        <button onClick={submit}>Post Comment</button>
      </div>
      {comments.map((c) => (
        <CommentItem key={c.id} comment={c} slug={slug} onReply={handleReply} />
      ))}
    </section>
  );
}

import { useEffect, useRef } from 'react';
import { api } from '../utils/api';

function getSessionId(): string {
  let id = sessionStorage.getItem('analytics_session');
  if (!id) {
    id = Math.random().toString(36).slice(2) + Date.now().toString(36);
    sessionStorage.setItem('analytics_session', id);
  }
  return id;
}

export function useReadDepthTracker(articleId: number) {
  const maxDepth = useRef(0);
  const startTime = useRef(Date.now());
  const reported = useRef(false);

  useEffect(() => {
    const sessionId = getSessionId();
    const params = new URLSearchParams(window.location.search);

    const handleScroll = () => {
      const scrollTop = window.scrollY;
      const docHeight = document.documentElement.scrollHeight - window.innerHeight;
      if (docHeight > 0) {
        const depth = Math.round((scrollTop / docHeight) * 100);
        maxDepth.current = Math.max(maxDepth.current, depth);
      }
    };

    const sendAnalytics = () => {
      if (reported.current) return;
      reported.current = true;
      const timeOnPage = Math.round((Date.now() - startTime.current) / 1000);
      api.post('/analytics/pageview', {
        article_id: articleId,
        session_id: sessionId,
        read_depth_percent: maxDepth.current,
        time_on_page_seconds: timeOnPage,
        referrer: document.referrer || null,
        utm_source: params.get('utm_source'),
        utm_medium: params.get('utm_medium'),
      }).catch(() => {});
    };

    window.addEventListener('scroll', handleScroll, { passive: true });
    window.addEventListener('beforeunload', sendAnalytics);

    return () => {
      window.removeEventListener('scroll', handleScroll);
      window.removeEventListener('beforeunload', sendAnalytics);
      sendAnalytics();
    };
  }, [articleId]);
}

import { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { api } from '../utils/api';

interface Suggestion { title: string; slug: string; }

export default function SearchBar() {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<Suggestion[]>([]);
  const [activeIndex, setActiveIndex] = useState(-1);
  const [open, setOpen] = useState(false);
  const navigate = useNavigate();
  const debounceRef = useRef<ReturnType<typeof setTimeout>>();

  useEffect(() => {
    if (query.length < 2) { setSuggestions([]); return; }
    if (debounceRef.current) clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(async () => {
      const res = await api.get(`/search/suggest?q=${encodeURIComponent(query)}`);
      setSuggestions(res.data.suggestions);
      setOpen(true);
      setActiveIndex(-1);
    }, 300);
  }, [query]);

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setActiveIndex((i) => Math.min(i + 1, suggestions.length - 1));
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      setActiveIndex((i) => Math.max(i - 1, -1));
    } else if (e.key === 'Enter') {
      if (activeIndex >= 0 && suggestions[activeIndex]) {
        navigate(`/articles/${suggestions[activeIndex].slug}`);
        setOpen(false);
      } else {
        navigate(`/search?q=${encodeURIComponent(query)}`);
      }
    } else if (e.key === 'Escape') {
      setOpen(false);
    }
  };

  return (
    <div className="search-bar" role="combobox" aria-expanded={open}>
      <input type="search" value={query} onChange={(e) => setQuery(e.target.value)}
             onKeyDown={handleKeyDown} onFocus={() => suggestions.length && setOpen(true)}
             onBlur={() => setTimeout(() => setOpen(false), 200)}
             placeholder="Search articles..." aria-label="Search articles" />
      {open && suggestions.length > 0 && (
        <ul className="suggestions" role="listbox">
          {suggestions.map((s, i) => (
            <li key={s.slug} role="option" aria-selected={i === activeIndex}
                className={i === activeIndex ? 'active' : ''}
                onMouseDown={() => navigate(`/articles/${s.slug}`)}>
              {s.title}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

interface PaginationProps {
  page: number;
  totalPages: number;
  onChange: (page: number) => void;
}

export default function Pagination({ page, totalPages, onChange }: PaginationProps) {
  const pages: number[] = [];
  const start = Math.max(1, page - 2);
  const end = Math.min(totalPages, page + 2);
  for (let i = start; i <= end; i++) pages.push(i);

  return (
    <nav className="pagination" aria-label="Page navigation">
      <button disabled={page <= 1} onClick={() => onChange(page - 1)}
              aria-label="Previous page">Previous</button>
      {start > 1 && (
        <>
          <button onClick={() => onChange(1)}>1</button>
          {start > 2 && <span aria-hidden="true">...</span>}
        </>
      )}
      {pages.map((p) => (
        <button key={p} onClick={() => onChange(p)}
                className={p === page ? 'active' : ''}
                aria-current={p === page ? 'page' : undefined}>{p}</button>
      ))}
      {end < totalPages && (
        <>
          {end < totalPages - 1 && <span aria-hidden="true">...</span>}
          <button onClick={() => onChange(totalPages)}>{totalPages}</button>
        </>
      )}
      <button disabled={page >= totalPages} onClick={() => onChange(page + 1)}
              aria-label="Next page">Next</button>
    </nav>
  );
}

from flask import request, make_response
from functools import wraps

def cache_control(max_age=0, public=False, stale_while_revalidate=0):
    """Decorator to set Cache-Control headers on responses."""
    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            response = make_response(f(*args, **kwargs))
            parts = []
            parts.append('public' if public else 'private')
            parts.append(f'max-age={max_age}')
            if stale_while_revalidate:
                parts.append(f'stale-while-revalidate={stale_while_revalidate}')
            response.headers['Cache-Control'] = ', '.join(parts)
            return response
        return decorated
    return decorator

def add_cache_headers(app):
    """Register after_request handler for default cache policies."""
    @app.after_request
    def set_cache(response):
        if 'Cache-Control' not in response.headers:
            if request.path.startswith('/static/'):
                response.headers['Cache-Control'] = 'public, max-age=31536000, immutable'
            elif request.path.startswith('/api/articles') and request.method == 'GET':
                response.headers['Cache-Control'] = 'public, max-age=60, stale-while-revalidate=300'
            elif request.path in ('/rss.xml', '/sitemap.xml'):
                response.headers['Cache-Control'] = 'public, max-age=3600'
        return response

import { useState, useRef, useEffect } from 'react';

interface LazyImageProps {
  src: string;
  alt: string;
  width?: number;
  height?: number;
  className?: string;
}

function cdnUrl(src: string, width: number): string {
  if (src.startsWith('/static/')) {
    return `${src}?w=${width}&fmt=webp&q=80`;
  }
  return src;
}

export default function LazyImage({ src, alt, width, height, className }: LazyImageProps) {
  const [loaded, setLoaded] = useState(false);
  const [inView, setInView] = useState(false);
  const imgRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const el = imgRef.current;
    if (!el) return;
    const observer = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) { setInView(true); observer.disconnect(); } },
      { rootMargin: '200px' }
    );
    observer.observe(el);
    return () => observer.disconnect();
  }, []);

  const optimizedSrc = width ? cdnUrl(src, width) : src;
  const placeholderSrc = width ? cdnUrl(src, 20) : src;

  return (
    <div ref={imgRef} className={`lazy-image-wrapper ${className || ''}`}
         style={{ aspectRatio: width && height ? `${width}/${height}` : undefined }}>
      {inView && (
        <>
          <img src={placeholderSrc} alt="" className="lazy-placeholder"
               style={{ filter: 'blur(20px)', position: 'absolute', inset: 0, width: '100%', height: '100%', objectFit: 'cover' }}
               aria-hidden="true" />
          <img src={optimizedSrc} alt={alt}
               onLoad={() => setLoaded(true)}
               style={{ opacity: loaded ? 1 : 0, transition: 'opacity 0.3s' }}
               loading="lazy" />
        </>
      )}
    </div>
  );
}
